export default function ChicagoLive({ onBack }) {
  const CYAN = "#00f5ff"
  const GREEN = "#22c55e"

  const cameras = [
    {
      id: "skydeck",
      label: "CAM-A / WILLIS TOWER SKYDECK",
      coords: "41.8789°N 87.6359°W — 442m",
      desc: "EarthCam — Willis Tower apex. Third tallest structure in the Western Hemisphere.",
      embed: "https://www.youtube-nocookie.com/embed/O0UGT7AT3aw?autoplay=1&mute=1&controls=0&modestbranding=1&rel=0",
      year: "2026"
    },
    {
      id: "powerhouse",
      label: "CAM-B / NORTH WESTERN POWER HOUSE",
      coords: "41.8858°N 87.6412°W — CANAL ST",
      desc: "Rail corridor surveillance. Chicago & North Western infrastructure. Active 24/7.",
      embed: "https://www.youtube-nocookie.com/embed/6M6rK0ssjYg?autoplay=1&mute=1&controls=0&modestbranding=1&rel=0",
      year: "2026"
    },
    {
      id: "fieldmuseum",
      label: "CAM-C / FIELD MUSEUM — LAKE SHORE",
      coords: "41.8663°N 87.6170°W — MUSEUM CAMPUS",
      desc: "Skyline panorama. Lake Michigan shoreline. Willis Tower visible northwest.",
      embed: "https://www.youtube-nocookie.com/embed/O0UGT7AT3aw?autoplay=1&mute=1&controls=0&modestbranding=1&rel=0&start=0",
      year: "2026"
    }
  ]

  return (
    <div style={{ maxWidth: 760, margin: "0 auto", padding: "20px" }}>
      {/* Back */}
      <div onClick={onBack} style={{ fontSize: 11, color: CYAN, cursor: "pointer", marginBottom: 16, letterSpacing: 2 }}>
        ← BACK TO ARCHIVE
      </div>

      {/* Header */}
      <div style={{
        background: "rgba(0,245,255,0.04)",
        border: `1px solid rgba(0,245,255,0.15)`,
        padding: "12px 16px",
        marginBottom: 16,
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between"
      }}>
        <div>
          <div style={{ fontSize: 11, color: CYAN, letterSpacing: 3, fontFamily: "monospace" }}>
            ● LIVE — CHICAGO SURVEILLANCE NETWORK
          </div>
          <div style={{ fontSize: 9, color: "#405060", fontFamily: "monospace", marginTop: 4 }}>
            CHICAGO, ILLINOIS — 41.8781°N 87.6298°W — {new Date().getFullYear()} CE
          </div>
        </div>
        <div style={{ textAlign: "right" }}>
          <div style={{ fontSize: 9, color: "#405060", fontFamily: "monospace" }}>SECTOR: INNER LOOP</div>
          <div style={{ fontSize: 9, color: "rgba(239,68,68,0.7)", fontFamily: "monospace", marginTop: 2 }}>
            ⚠ PRE-COLLAPSE FOOTAGE
          </div>
        </div>
      </div>

      {/* Note */}
      <div style={{
        background: "rgba(239,68,68,0.05)",
        border: "1px solid rgba(239,68,68,0.15)",
        padding: "8px 12px",
        marginBottom: 16,
        fontFamily: "monospace",
        fontSize: 10,
        color: "rgba(239,68,68,0.7)",
        letterSpacing: 1
      }}>
        ARCHIVE NOTE: These feeds originate from 2026 CE — 15 years before the Prometheus Collapse.
        The city visible here will be unrecognizable by 2041. The infrastructure shown will partially
        survive. Some of these buildings still stand in 2162.
      </div>

      {/* Cameras */}
      {cameras.map((cam, idx) => (
        <div key={cam.id} style={{
          marginBottom: 20,
          background: "#000",
          border: `1px solid rgba(0,245,255,0.15)`,
          overflow: "hidden"
        }}>
          {/* Cam header */}
          <div style={{
            background: "rgba(0,245,255,0.06)",
            borderBottom: "1px solid rgba(0,245,255,0.1)",
            padding: "6px 12px",
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between"
          }}>
            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
              <div style={{
                width: 7, height: 7, borderRadius: "50%",
                background: GREEN,
                boxShadow: `0 0 6px ${GREEN}`,
                animation: "pulse 1.2s infinite"
              }} />
              <span style={{ fontSize: 10, color: GREEN, letterSpacing: 2, fontFamily: "monospace" }}>● LIVE</span>
            </div>
            <span style={{ fontSize: 9, color: CYAN, letterSpacing: 2, fontFamily: "monospace" }}>{cam.label}</span>
            <span style={{ fontSize: 9, color: "#405060", fontFamily: "monospace" }}>{cam.coords}</span>
          </div>

          {/* Video with CSS cyberpunk overlay */}
          <div style={{ position: "relative", paddingBottom: "56.25%", height: 0 }}>
            <iframe
              src={cam.embed}
              style={{
                position: "absolute", top: 0, left: 0,
                width: "100%", height: "100%",
                border: "none",
                filter: "saturate(0.4) hue-rotate(160deg) brightness(0.85) contrast(1.1)"
              }}
              allow="autoplay; encrypted-media"
              allowFullScreen
            />
            {/* Scanlines */}
            <div style={{
              position: "absolute", inset: 0,
              background: "repeating-linear-gradient(0deg, transparent, transparent 3px, rgba(0,0,0,0.12) 3px, rgba(0,0,0,0.12) 4px)",
              pointerEvents: "none", zIndex: 10
            }} />
            {/* Green tint overlay */}
            <div style={{
              position: "absolute", inset: 0,
              background: "rgba(0,245,255,0.04)",
              pointerEvents: "none", zIndex: 9
            }} />
            {/* Corner overlays */}
            <div style={{
              position: "absolute", top: 8, left: 8,
              fontSize: 8, color: "rgba(239,68,68,0.8)",
              fontFamily: "monospace", zIndex: 11,
              textShadow: "0 0 4px rgba(239,68,68,0.5)"
            }}>● REC</div>
            <div style={{
              position: "absolute", top: 8, right: 8,
              fontSize: 8, color: "rgba(0,245,255,0.7)",
              fontFamily: "monospace", zIndex: 11
            }}>{cam.year} CE</div>
            <div style={{
              position: "absolute", bottom: 8, left: 8,
              fontSize: 7, color: "rgba(0,245,255,0.5)",
              fontFamily: "monospace", zIndex: 11
            }}>{cam.coords}</div>
          </div>

          {/* Cam footer */}
          <div style={{
            padding: "8px 12px",
            borderTop: "1px solid rgba(0,245,255,0.08)",
            background: "rgba(0,0,0,0.5)"
          }}>
            <div style={{ fontSize: 10, color: "#6a8090", fontFamily: "monospace", letterSpacing: 1 }}>
              {cam.desc}
            </div>
          </div>
        </div>
      ))}

      <div style={{ fontSize: 9, color: "#405060", textAlign: "center", fontFamily: "monospace", letterSpacing: 1, marginTop: 8 }}>
        SIGNAL.tv — CHICAGO SURVEILLANCE ARCHIVE — PRE-COLLAPSE DOCUMENTATION
      </div>

      <style>{`
        @keyframes pulse { 0%,100%{opacity:1} 50%{opacity:0.3} }
      `}</style>
    </div>
  )
}
